"""
Enhanced PowerShell hook script generator with robust error handling.
"""


def generate_hook_script(settings_path: str) -> str:
    """Generate the PowerShell hook script with enhanced error handling."""

    script = f'''# Auto-continue hook script
# Generated by API切换器
# Enhanced with robust error handling

$ErrorActionPreference = "Stop"

# Logging function
function Write-Log {{
    param([string]$Message, [string]$Level = "INFO")
    $timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
    $logMessage = "$timestamp [$Level] $Message"
    Write-Error $logMessage
}}

try {{
    # Read settings with error handling
    $settingsPath = "{settings_path}"
    if (-not (Test-Path $settingsPath)) {{
        Write-Log "Settings file not found: $settingsPath" "WARN"
        exit 0  # Allow stop if no settings
    }}

    try {{
        $settings = Get-Content $settingsPath -Raw -ErrorAction Stop | ConvertFrom-Json -ErrorAction Stop
    }} catch {{
        Write-Log "Failed to parse settings JSON: $_" "ERROR"
        exit 0  # Allow stop if settings invalid
    }}

    if (-not $settings.enabled) {{
        exit 0  # Allow stop if disabled
    }}

    # Validate settings
    if ($null -eq $settings.max_continuations -or $settings.max_continuations -lt 0) {{
        Write-Log "Invalid max_continuations value" "ERROR"
        exit 0
    }}

    # Read stdin (hook input) with timeout protection
    $stdinLines = @()
    $timeout = 5  # seconds
    $startTime = Get-Date
    while ($null -ne ($line = [Console]::ReadLine())) {{
        $stdinLines += $line
        if (((Get-Date) - $startTime).TotalSeconds -gt $timeout) {{
            Write-Log "Stdin read timeout" "WARN"
            break
        }}
    }}
    $stdin = $stdinLines -join "`n"

    if ([string]::IsNullOrWhiteSpace($stdin)) {{
        exit 0  # Allow stop if no input
    }}

    # Parse input JSON with error handling
    try {{
        $input = $stdin | ConvertFrom-Json -ErrorAction Stop
    }} catch {{
        Write-Log "Failed to parse input JSON: $_" "ERROR"
        exit 0
    }}

    # Determine provider based on input structure
    $isClaude = $null -ne $input.hook_event_name
    $isCodex = $null -eq $input.hook_event_name

    # Get session ID and last message
    $sessionId = if ($isClaude) {{ $input.session_id }} else {{ $input.session_id }}
    $lastMessage = if ($isClaude) {{ $input.last_assistant_message }} else {{ $input.last_message }}
    $hookEvent = if ($isClaude) {{ $input.hook_event_name }} else {{ "Stop" }}
    $agentId = if ($isClaude) {{ $input.agent_id }} else {{ $null }}

    if ([string]::IsNullOrWhiteSpace($lastMessage)) {{
        exit 0  # Allow stop if no message
    }}

    # Build state key
    $stateKey = "$sessionId-$hookEvent"
    if ($agentId) {{
        $stateKey = "$stateKey-$agentId"
    }}

    # Load state with file locking
    $stateDir = Split-Path $settingsPath
    $statePath = Join-Path $stateDir "auto_continue_stop_state.json"
    $lockPath = "$statePath.lock"

    # Simple file-based locking (wait up to 2 seconds)
    $lockWait = 0
    while ((Test-Path $lockPath) -and $lockWait -lt 20) {{
        Start-Sleep -Milliseconds 100
        $lockWait++
    }}

    if ($lockWait -ge 20) {{
        Write-Log "Failed to acquire state file lock" "WARN"
        exit 0  # Allow stop if can't acquire lock
    }}

    # Create lock file
    try {{
        New-Item -Path $lockPath -ItemType File -Force | Out-Null
    }} catch {{
        Write-Log "Failed to create lock file: $_" "WARN"
        exit 0
    }}

    try {{
        # Load state
        $state = @{{}}
        if (Test-Path $statePath) {{
            try {{
                $stateContent = Get-Content $statePath -Raw -ErrorAction Stop
                $state = $stateContent | ConvertFrom-Json -ErrorAction Stop -AsHashtable
            }} catch {{
                Write-Log "Failed to parse state JSON, resetting state: $_" "WARN"
                $state = @{{}}
            }}
        }}

        # Get continuation count
        $count = if ($state.ContainsKey($stateKey)) {{ $state[$stateKey] }} else {{ 0 }}

        # Check max continuations
        if ($count -ge $settings.max_continuations) {{
            # Log and allow stop
            $logPath = Join-Path $stateDir "auto_continue_stop_log.jsonl"
            $logEntry = @{{
                timestamp = (Get-Date -Format "o")
                session_id = $sessionId
                hook_event = $hookEvent
                agent_id = $agentId
                decision = "allow_stop"
                reason = "max_continuations_reached"
                count = $count
            }} | ConvertTo-Json -Compress
            try {{
                Add-Content -Path $logPath -Value $logEntry -ErrorAction Stop
            }} catch {{
                Write-Log "Failed to write log: $_" "WARN"
            }}
            exit 0
        }}

        # Check conservative mode for Claude Code
        if ($isClaude -and $settings.conservative_mode -and $input.stop_hook_active) {{
            exit 0  # Allow stop in conservative mode when already continuing
        }}

        # Check blocker patterns with error handling
        $isBlocked = $false
        if ($settings.blocker_patterns) {{
            foreach ($pattern in $settings.blocker_patterns) {{
                try {{
                    if ($lastMessage -match $pattern) {{
                        $isBlocked = $true
                        break
                    }}
                }} catch {{
                    Write-Log "Invalid blocker pattern: $pattern" "WARN"
                }}
            }}
        }}

        if ($isBlocked) {{
            exit 0  # Allow stop if blocked
        }}

        # Check incomplete patterns with error handling
        $isIncomplete = $false
        if ($settings.incomplete_patterns) {{
            foreach ($pattern in $settings.incomplete_patterns) {{
                try {{
                    if ($lastMessage -match $pattern) {{
                        $isIncomplete = $true
                        break
                    }}
                }} catch {{
                    Write-Log "Invalid incomplete pattern: $pattern" "WARN"
                }}
            }}
        }}

        if (-not $isIncomplete) {{
            exit 0  # Allow stop if complete
        }}

        # Decision: block stop and continue
        $count++
        $state[$stateKey] = $count

        # Save state with atomic write
        try {{
            $tempPath = "$statePath.tmp"
            $state | ConvertTo-Json | Set-Content $tempPath -ErrorAction Stop
            Move-Item -Path $tempPath -Destination $statePath -Force -ErrorAction Stop
        }} catch {{
            Write-Log "Failed to save state: $_" "ERROR"
        }}

        # Log decision
        $logPath = Join-Path $stateDir "auto_continue_stop_log.jsonl"
        $logEntry = @{{
            timestamp = (Get-Date -Format "o")
            session_id = $sessionId
            hook_event = $hookEvent
            agent_id = $agentId
            decision = "block_stop"
            reason = "incomplete_work_detected"
            count = $count
            continuation_prompt = $settings.continuation_prompt
        }} | ConvertTo-Json -Compress
        try {{
            Add-Content -Path $logPath -Value $logEntry -ErrorAction Stop
        }} catch {{
            Write-Log "Failed to write log: $_" "WARN"
        }}

        # Output decision
        if ($isClaude) {{
            # Claude Code format
            $output = @{{
                decision = "block"
                reason = $settings.continuation_prompt
                suppressOutput = $true
            }} | ConvertTo-Json
            Write-Output $output
        }} else {{
            # Codex format
            $output = @{{
                continue = $true
                message = $settings.continuation_prompt
            }} | ConvertTo-Json
            Write-Output $output
        }}

    }} finally {{
        # Always remove lock file
        if (Test-Path $lockPath) {{
            try {{
                Remove-Item -Path $lockPath -Force -ErrorAction SilentlyContinue
            }} catch {{
                # Ignore lock removal errors
            }}
        }}
    }}

}} catch {{
    Write-Log "Unexpected error: $_" "ERROR"
    exit 0  # Allow stop on unexpected error
}}

exit 0
'''

    return script
